/**
 * Rebuild monthly pool carry for one employee after leave register debits change.
 *
 * **Step 1 ŌĆö strip (clean slate)** ŌĆö `stripMonthlyPoolTransferArtifactsFromMonths` on **every** FY slot, all `LeaveRegisterYear`
 * rows for the employee, oldest FY first:
 * - **Delete** all FY-slot pool carry rows: `autoGeneratedType` `MONTHLY_POOL_TRANSFER_OUT_*` / `IN_*`, and legacy
 *   `autoGenerated` CL/C/CCL/EL rows whose reason matches the carry service ŌĆ£Transfer in/out ŌĆö unused monthly apply pool ŌĆ”ŌĆØ
 *   text (covers duplicates when `autoGeneratedType` was never set).
 * - **Clear** carry metadata: `poolCarryForwardIn`, `poolCarryForwardOut`, `poolCarryForwardOutAt`, `poolCarryForwardFromLabel`,
 *   `poolCarryForwardAllocation`.
 * - **Undo** prior carry-in bumps on scheduled pool counts: subtract rolled-in `cl` / `ccl` / `el` from `clCredits` /
 *   `compensatoryOffs` / `elCredits` so each month reflects **native credits only** (no ŌĆ£already carried inŌĆØ double stack).
 *
 * **Step 2 ŌĆö replay (oldest closed month first)** ŌĆö `processPayrollCycleCarryForward(pm, py, { employeeId })` once per
 * **closed** payroll slot before the open cycle (`asOf`), sorted by `payPeriodEnd` ascending (Jan ŌåÆ Feb ŌåÆ ŌĆ”):
 * - Syncs monthly-apply consumed/locked from Leave rows, then for each type (policy roll flags apply): unused pool
 *   **balance** Ōēł **scheduled credits ŌłÆ used ŌłÆ CL slot lock** (CCL/EL without that lock; see `monthlyPoolCarryForwardService`).
 * - Posts **new** `MONTHLY_POOL_TRANSFER_OUT_*` DEBIT on the **closing** month and matching `MONTHLY_POOL_TRANSFER_IN_*`
 *   CREDIT on the **next** month, bumps next slot pool fields, sets carry metadata.
 * - Cron-wide runs skip a month if `poolCarryForwardOutAt` is set; **scoped `employeeId` runs do not skip**, so replay always
 *   applies after a strip.
 *
 * The **open** payroll month (e.g. May while May is current) is not replayed ŌĆö no transfer-out for it until that period closes.
 */

const mongoose = require('mongoose');
const LeaveRegisterYear = require('../model/LeaveRegisterYear');
const leaveRegisterYearService = require('./leaveRegisterYearService');
const monthlyPoolCarryForwardService = require('./monthlyPoolCarryForwardService');
const dateCycleService = require('./dateCycleService');
const leaveRegisterYearLedgerService = require('./leaveRegisterYearLedgerService');
const leaveRegisterYearMonthlyApplyService = require('./leaveRegisterYearMonthlyApplyService');
const { createISTDate, getTodayISTDateString } = require('../../shared/utils/dateUtils');

function toObjectId(employeeId) {
  const s = String(employeeId || '').trim();
  if (!s) return null;
  return mongoose.Types.ObjectId.isValid(s) ? new mongoose.Types.ObjectId(s) : employeeId;
}

/**
 * @param {import('mongoose').Types.ObjectId|string} employeeId
 * @param {object} [opts]
 * @param {Date} [opts.asOfDate] ŌĆö defaults to now (determines which payroll cycle is ŌĆ£openŌĆØ)
 * @param {number} [opts.throughPayrollMonth] ŌĆö optional cap (e.g. 5 = do not run carry for Jun+)
 * @param {number} [opts.throughPayrollYear] ŌĆö optional with throughPayrollMonth
 * @returns {Promise<{ ok: boolean, error?: string, yearsTouched?: number, edgesApplied?: number, carriesPosted?: number, carryErrors?: number, carryCutoffIso?: string }>}
 */
async function reconcilePoolCarryChainAfterRegisterChange(employeeId, opts = {}) {
  const eid = toObjectId(employeeId);
  if (!eid) return { ok: false, error: 'employeeId required' };

  const asOf = opts.asOfDate ? new Date(opts.asOfDate) : new Date();
  const capM = opts.throughPayrollMonth;
  const capY = opts.throughPayrollYear;

  try {
    const fyDocs = await LeaveRegisterYear.find({ employeeId: eid }).sort({ financialYearStart: 1 });
    for (const doc of fyDocs) {
      leaveRegisterYearService.stripMonthlyPoolTransferArtifactsFromMonths(doc.months);
      doc.markModified('months');
      await doc.save();
    }

    const periodInfo = await dateCycleService.getPeriodInfo(asOf);
    const currentCycleStart = periodInfo?.payrollCycle?.startDate;
    const carryCutoff =
      currentCycleStart != null ? new Date(currentCycleStart) : createISTDate(getTodayISTDateString());

    const closings = [];
    const refreshed = await LeaveRegisterYear.find({ employeeId: eid }).sort({ financialYearStart: 1 }).lean();
    for (const d of refreshed) {
      for (const slot of d.months || []) {
        if (!slot.payPeriodEnd) continue;
        if (!leaveRegisterYearService.isPayrollPeriodClosedBeforeAsOf(slot.payPeriodEnd, carryCutoff)) {
          continue;
        }
        closings.push({
          pm: Number(slot.payrollCycleMonth),
          py: Number(slot.payrollCycleYear),
          t: new Date(slot.payPeriodEnd).getTime(),
        });
      }
    }
    const seen = new Set();
    let ordered = closings
      .filter((c) => {
        if (!Number.isFinite(c.pm) || !Number.isFinite(c.py)) return false;
        const k = `${c.py}-${c.pm}`;
        if (seen.has(k)) return false;
        seen.add(k);
        return true;
      })
      .sort((a, b) => a.t - b.t);

    if (capM != null && Number.isFinite(Number(capM))) {
      const beforeCap = ordered.length;
      ordered = ordered.filter((c) => {
        if (Number(c.pm) > Number(capM)) return false;
        if (capY != null && Number.isFinite(Number(capY)) && Number(c.py) !== Number(capY)) return false;
        return true;
      });
      if (beforeCap !== ordered.length) {
        console.log(
          `[leaveRegisterPoolCarryReconcile] throughPayrollMonth<=${capM}${
            capY != null && Number.isFinite(Number(capY)) ? ` year=${capY}` : ''
          }: ${beforeCap} ŌåÆ ${ordered.length} closings`
        );
      }
    }

    if (ordered.length > 0) {
      const f = ordered[0];
      const l = ordered[ordered.length - 1];
      console.log(
        `[leaveRegisterPoolCarryReconcile] replay ${ordered.length} closed month(s) oldestŌåÆnewest (first ${f.py}/${f.pm}, last ${l.py}/${l.pm}) by payPeriodEnd`
      );
    }

    let carriesPosted = 0;
    let carryErrors = 0;
    for (const c of ordered) {
      const r = await monthlyPoolCarryForwardService.processPayrollCycleCarryForward(c.pm, c.py, {
        employeeId: eid,
      });
      carriesPosted += Number(r?.carriesPosted) || 0;
      if (Array.isArray(r?.errors) && r.errors.length) {
        carryErrors += r.errors.length;
      }
    }

    await leaveRegisterYearLedgerService.recalculateRegisterBalances(eid, 'CL', null);
    await leaveRegisterYearLedgerService.recalculateRegisterBalances(eid, 'CCL', null);
    await leaveRegisterYearLedgerService.recalculateRegisterBalances(eid, 'EL', null);

    try {
      await leaveRegisterYearMonthlyApplyService.syncStoredMonthApplyFieldsForEmployeeDate(eid, asOf);
    } catch (syncErr) {
      console.warn('[leaveRegisterPoolCarryReconcile] monthlyApply sync:', syncErr?.message || syncErr);
    }

    const fy = periodInfo?.financialYear?.name;
    if (fy) {
      const { scheduleRegisterDisplaySnapshotSync } = require('./leaveRegisterYearRegisterDisplaySyncService');
      scheduleRegisterDisplaySnapshotSync(eid, fy);
    }

    return {
      ok: true,
      yearsTouched: fyDocs.length,
      edgesApplied: ordered.length,
      carriesPosted,
      carryErrors,
      carryCutoffIso: carryCutoff?.toISOString?.() || String(carryCutoff),
    };
  } catch (e) {
    const msg = e?.message || String(e);
    console.warn('[leaveRegisterPoolCarryReconcile] failed:', msg);
    return { ok: false, error: msg };
  }
}

/** CL / CCL / EL debits affect monthly apply pool carry; skip for LOP-only etc. */
function leaveTypeAffectsMonthlyPoolCarry(leaveType) {
  const u = String(leaveType || '').trim().toUpperCase();
  return u === 'CL' || u === 'CCL' || u === 'EL';
}

module.exports = {
  reconcilePoolCarryChainAfterRegisterChange,
  leaveTypeAffectsMonthlyPoolCarry,
};
